struct ContentView: View {
    @State private var apiResult: String = "Tap to fetch from API"
    @State private var legacyResult: String = "Tap to fetch from Legacy"

    var body: some View {
        VStack(spacing: 20) {
            Text("API Server (HTTPS)")
                .font(.headline)
            Button("Fetch from API") {
                fetchData(from: URL(string: "https://api.example.com/data")!, resultBinding: $apiResult)
            }
            Text(apiResult)
                .padding()
