                .cornerRadius(8)

            Divider()

            Text("Legacy System (HTTP)")
                .font(.headline)
            Button("Fetch from Legacy") {
                fetchData(from: URL(string: "http://legacy.internal/status")!, resultBinding: $legacyResult)
            }
            Text(legacyResult)
                .padding()
                .background(Color.gray.opacity(0.1))
                .cornerRadius(8)
        }
        .padding()
    }

    private func fetchData(from url: URL, resultBinding: Binding<String>) {
        resultBinding.wrappedValue = "Fetching..."

        let task = URLSession.shared.dataTask(with: url) { data, response, error in
            DispatchQueue.main.async {
                if let error = error {
                    resultBinding.wrappedValue = "Error: \(error.localizedDescription)"
                    print("Error fetching from \(url.absoluteString): \(error)")
                    return
                }

                guard let httpResponse = response as? HTTPURLResponse else {
                    resultBinding.wrappedValue = "Invalid response"
                    print("Invalid response from \(url.absoluteString)")
                    return
                }

                if httpResponse.statusCode == 200 {
                    if let data = data, let str = String(data: data, encoding: .utf8) {
                        resultBinding.wrappedValue = "Success: \(str.prefix(100))..." // Display first 100 characters
                    } else {
                        resultBinding.wrappedValue = "Success: No data or cannot decode"
                    }
                } else {
                    resultBinding.wrappedValue = "HTTP Status: \(httpResponse.statusCode)"
                }
            }
        }
        task.resume()
    }
}

